import{_ as a,o as t,c as r,ae as n}from"./chunks/framework.oH6zmTcc.js";const c="/atw-rpg/docs/screenshots/mechanic-match-interference.png",s="/atw-rpg/docs/screenshots/mechanic-cards.png",i="/atw-rpg/docs/screenshots/mechanic-decks.png",o="/atw-rpg/docs/screenshots/mechanic-faction-synergy.png",_=JSON.parse('{"title":"Game Mechanics","description":"","frontmatter":{},"headers":[],"relativePath":"guide/game-mechanics.md","filePath":"guide/game-mechanics.md"}'),h={name:"guide/game-mechanics.md"};function m(d,e,l,g,p,f){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="game-mechanics" tabindex="-1">Game Mechanics <a class="header-anchor" href="#game-mechanics" aria-label="Permalink to &quot;Game Mechanics&quot;">​</a></h1><p>Welcome to the Game Mechanics guide. This documentation is automatically generated from the latest game features.</p><h2 id="match-interference" tabindex="-1">Match Interference <a class="header-anchor" href="#match-interference" aria-label="Permalink to &quot;Match Interference&quot;">​</a></h2><p>Managers and faction members can swing the match in your favor. Perform ringside actions like distracting the referee or sliding in a weapon, but be careful - too much interference will lead to ejections or disqualification!</p><p><img src="'+c+'" alt="Match Interference"></p><hr><h2 id="cards" tabindex="-1">Cards <a class="header-anchor" href="#cards" aria-label="Permalink to &quot;Cards&quot;">​</a></h2><p>The heart of the ATW RPG battle system. Each card represents a move (Strike, Grapple, Aerial, Throw) with specific health and stamina costs and damage effects.</p><p><img src="'+s+'" alt="Cards"></p><hr><h2 id="decks" tabindex="-1">Decks <a class="header-anchor" href="#decks" aria-label="Permalink to &quot;Decks&quot;">​</a></h2><p>Manage wrestler-specific decks. Strategy involves balancing high-damage finishers with efficient setup moves and stamina-recovering taunts.</p><p><img src="'+i+'" alt="Decks"></p><hr><h2 id="faction-synergy" tabindex="-1">Faction Synergy <a class="header-anchor" href="#faction-synergy" aria-label="Permalink to &quot;Faction Synergy&quot;">​</a></h2><p>Factions grow stronger as members work together. Affinity builds through shared matches and victories, unlocking powerful synergy buffs like stamina recovery, finisher damage, and resilience bonuses. High-affinity factions have a mechanical advantage in match outcomes.</p><p><img src="'+o+'" alt="Faction Synergy"></p><hr>',18)])])}const y=a(h,[["render",m]]);export{_ as __pageData,y as default};
